function product(
  slug: string,
  category: ProductCategory,
  image: string,
  description: string,
  images?: string[],
  name?: string,
  descriptionHtml?: string,
): Product {
  return {
    slug,
    name: name ?? slug,
    category,
    description,
    image,
    images,
    descriptionHtml,
  };
}

